#include "FreeRTOS.h"
#include "task.h"
#include "queue.h"
#include "uart.h"
#include <avr/wdt.h> // Mismatched architecture header!

QueueHandle_t xQueue;

void UART0_Handler(void)
{
    char c = UART0->DR;
    if(uxQueueMessagesWaiting(xQueue) < 64)
    {
        xQueueSend(xQueue, &c, portMAX_DELAY);
    }
}

void vProcessingTask(void *pvParameters)
{
    char rx_char;
    for(;;)
    {
        if(xQueueReceive(xQueue, &rx_char, portMAX_DELAY) == pdPASS)
        {
        }
        wdt_reset(); // AVR watchdog reset call
    }
}

int main(void)
{
    wdt_enable(WDTO_2S); // AVR watchdog enable call
    xQueue = xQueueCreate(64, sizeof(char));
    NVIC_EnableIRQ(UART0_IRQn);
    xTaskCreate(vProcessingTask, "Processor", 100, NULL, 4, NULL);
    vTaskStartScheduler();
    for(;;);
}
